// ======================================================
// WEWEB – KOMPLETNÍ, OPRAVENÝ A ODOLNÝ KÓD
// ======================================================

// 1) DATA Z RPC
const duchod =
  context.workflow['8b2916df-d7a4-4e89-b1af-a5488cb48f44']
    ?.result?.[0]?.duchod ?? 0;

// 2) DATA Z VARIABLES
const mesicniCastka = Number(variables['51b18477-0d15-47bb-8223-4d0a25c61e6a']) || 0;






// ❗️POUŽÍVÁME NÁZEV PROMĚNNÉ, NE UUID
const rawBirth = variables.birth_date;


// ======================================================
// 3) VALIDACE DAT
// ======================================================
if (!rawBirth) {
  return {
    error: true,
    message: 'birth_date je undefined nebo prázdné',
    birth_date: rawBirth
  };
}

const birthDate = new Date(rawBirth);

if (isNaN(birthDate.getTime())) {
  return {
    error: true,
    message: 'Neplatné datum narození',
    birth_date: rawBirth
  };
}


// ======================================================
// 4) ROZDÍL (měsíční potřeba − důchod)
// ======================================================
const rozdilMesicne = mesicniCastka - duchod;


// ======================================================
// 5) VÝPOČET MĚSÍCŮ DO 65 LET
// ======================================================
const today = new Date();

let monthsTo65 =
  (65 - (today.getFullYear() - birthDate.getFullYear())) * 12 +
  (birthDate.getMonth() - today.getMonth());

monthsTo65 = Math.max(0, Math.floor(monthsTo65));


// ======================================================
// 6) CELKOVÁ ČÁSTKA DO 65 LET
// ======================================================
const celkovaCastka = rozdilMesicne * monthsTo65;


// ======================================================
// 7) RETURN
// ======================================================
return {
  duchod,
  rozdilMesicne,
  monthsTo65,
  celkovaCastka
};

